        connector: CopilotConnector,
        status: (any StatusConnector)? = nil,
        monitor: CopilotActiveAccountMonitor? = nil,
        logger: FileLogger = Loggers.copilot,
        sanitizer: CopilotPayloadSanitizer = CopilotPayloadSanitizer()
